define("text!../../../res/views/CartCreditCardPaymentLayout.html!strip", [], function() {
    return '<div class="list-container main-content"> <div class="list-header"> <h1 class="list-header-title cart-title-label container">{{{ViewModel.TitleLabel}}}</h1> </div> <div class="container {{loading}}"> <div class="loading-container billing-form"> <h3>{{{ViewModel.EnterYourBillingInformationLabel}}}</h3> <div class="field-container"> <p class="input-title">{{{ViewModel.NameOnCardLabel}}}</p> <input id="nameOnCard" class="input-field large-input-field" type="text"> <div id="name-on-card-error" class="field-error large-input-field">{{{ViewModel.PleaseVerifyEntry}}}</div> </div> <div class="field-container"> <p class="input-title">{{{ViewModel.CardNumberLabel}}}</p> <div id="cardNumber" class="input-field large-input-field cc-input-field"></div> <div id="card-number-error" class="field-error large-input-field">{{{ViewModel.CardNotSupportedTryAnotherCard}}}</div> <div id="card-brand"> <img id="american_express" class="credit-card-logo" src="{{getImageSrc imageResource.AmericanExpressIcon}}" alt="American Express"> <img id="discover" class="credit-card-logo" src="{{getImageSrc imageResource.DiscoverIcon}}" alt="Discover"> <img id="mastercard" class="credit-card-logo" src="{{getImageSrc imageResource.MasterCardIcon}}" alt="Mastercard"> <img id="visa" class="credit-card-logo" src="{{getImageSrc imageResource.VisaIcon}}" alt="Visa"> </div> </div> <div id="expiry-date-cvv-container"> <div class="field-container"> <p class="input-title">{{{ViewModel.ExpiryDateLabel}}}</p> <div id="expiryDate" class="input-field small-input-field cc-input-field"></div> <div id="expiry-date-error" class="field-error">{{{ViewModel.PleaseVerifyEntry}}}</div> </div> <div class="field-container"> <p class="input-title">{{{ViewModel.CvvLabel}}}</p> <div id="cvv" class="input-field small-input-field cc-input-field"></div> <div id="cvv-error" class="field-error">{{{ViewModel.PleaseVerifyEntry}}}</div> </div> <div class="field-container"> <p class="input-title">&nbsp;</p> <div id="cvv-helper-container">?</div> </div> </div> <div style="clear:both;"></div> <div class="field-container"> <div id="zipCodeContainer"> <p class="input-title">{{{ViewModel.ZipCodeOrPostalCodeLabel}}}</p> <input id="zipCode" class="input-field small-input-field" type="text" maxlength="10"> <div id="zip-code-error" class="field-error">{{{ViewModel.PleaseVerifyEntry}}}</div> </div> </div> <div id="payment-container"> <button id="submit-button" class="checkout-button" type="button">{{{ViewModel.SubmitLabel}}}</button> <div style="clear:both;"></div> <div id="secure-payment-container"> {{{ViewModel.SecurePaymentWithLabel}}} <img src="{{getImageSrc imageResource.PaysafeLogo}}" width="50px"> </div> </div> <script type="text/javascript"> function initCreditCardFields(apiKey, environment, cardsSupportedIds, submitPaymentFn, handleFieldsErrorsFn, showErrorFn) {\n                    var options = {\n                        environment: environment,\n\n                        // set the CSS selectors to identify the payment field divs above\n                        // set the placeholder text to display in these fields\n                        fields: {\n                            cardNumber: {\n                                selector: "#cardNumber",\n                                placeholder: ""\n                            },\n                            expiryDate: {\n                                selector: "#expiryDate",\n                                placeholder: "MM / YY"\n                            },\n                            cvv: {\n                                selector: "#cvv",\n                                placeholder: ""\n                            }\n                        },\n                        style: {}\n                    };\n\n                    function getInvalidNonCriticalFields() {\n                        var errors = [];\n\n                        if ($.trim($("#zipCode").val()) === \'\') {\n                            errors.push("zipCode")\n                        }\n\n                        if ($.trim($("#nameOnCard").val()) === \'\') {\n                            errors.push("nameOnCard")\n                        }\n\n                        return errors;\n                    }\n\n                    function normalizeCardBrand(cardBrand){\n                        return cardBrand.replace(/ /g, \'_\').toLowerCase();\n                    }\n\n                    function isCardSupported(cardBrand){\n                        return (cardBrand && cardsSupportedIds.indexOf(normalizeCardBrand(cardBrand)) >= 0);\n                    }\n\n                    function resetFieldErrors() {\n                        $(".field-error").hide();\n                    }\n\n                    // initalize the hosted iframes using the SDK setup function\n                    paysafe.fields.setup(apiKey, options, function (instance, error) {\n                        function submit() {\n                            var nonCriticalErrors = getInvalidNonCriticalFields();\n\n                            instance.tokenize(function (instance, criticalFieldsErrorMessage, result) {\n                                if (!criticalFieldsErrorMessage && nonCriticalErrors.length === 0 && isCardSupported(instance.getCardBrand())) {\n                                    // Gather extra fields, not sent to Paysafe.\n                                    var nameOnCard = $("#nameOnCard").val();\n                                    var zip = $("#zipCode").val();\n\n                                    // Since no errors, reset field errors before submit.\n                                    resetFieldErrors();\n\n                                    submitPaymentFn(result.token, zip, nameOnCard);\n                                } else {\n                                    handleFieldsErrorsFn(criticalFieldsErrorMessage, nonCriticalErrors, isCardSupported(instance.getCardBrand()));\n                                }\n                            });\n                        }\n\n                        // When the customer clicks Pay Now,\n                        // call the SDK tokenize function to create\n                        // a single-use payment token corresponding to the card details entered\n                        document.getElementById("submit-button").addEventListener("mousedown", function () {\n                            try {\n                                submit();\n                            } catch (e) {\n                                showErrorFn(e);\n                            }\n                        }, false);\n\n                        instance.cardBrandRecognition(function (instance, event) {\n                            var activeCardBrand = instance.getCardBrand();\n\n                            // Grey out (change the color) of "inactive" card\n                            // If a VISA card was entered, then MasterCard, American Express, Discover logos will become grey\n                            if (activeCardBrand) {\n                                $.each(cardsSupportedIds, function (index, card) {\n                                    $("#" + card).addClass("grey-out");\n                                });\n\n                                var cardBrandNormalised = normalizeCardBrand(activeCardBrand);\n                                $("#" + cardBrandNormalised).removeClass("grey-out");\n                            } else {\n                                $.each(cardsSupportedIds, function (index, card) {\n                                    $("#" + card).removeClass("grey-out");\n                                });\n                            }\n                        });\n                    });\n                }\n                function emptyCreditCardFields() {\n                    $(".input-field.cc-input-field").empty();\n                } <\/script> <div class="loading-spinner"></div> </div> </div> </div> {{on "click" "#cvv-helper-container" "showCvvExplained()"}} '
});
