define("text!../../../res/views/LibrarySongItemLayout.html!strip", [], function() {
    return '<img class="button song-preview-button library-song-item-show-more-info" src="{{getImageSrc ViewModel.ItemViewModel.ShowMoreInfoItem.Icon}}" alt> <div class="song-text-container library-song-text-container"><div class="song-title-container library-song-title-container"><div class="song-title library-song-item-title">{{{ViewModel.ItemViewModel.ShowMoreInfoItem.Text}}}</div>{{#compare ViewModel.ItemViewModel.Ratings "!==" "G"}}<div class="song-rating-container library-song-item-rating-container">{{{ViewModel.ItemViewModel.Ratings}}}</div>{{/compare}}</div><div class="song-artist-container library-song-item-artist-container"><div class="song-artist-prefix-container"><div class="label-view song-artist-prefix library-song-item-artist-label">{{{ViewModel.ItemViewModel.PrefixLabel}}}</div></div><div class="song-artist-list-container library-song-artist-list-container"><div class="song-artist-list library-song-item-artist-value">{{#eachList ViewModel.ItemViewModel.ArtistItems}}<div class="subview-artist{{@index}} button {{#compare (evaluate @index \'>\' 0) \'||\' (evaluate this.HasAction \'===\' false) }}disabled{{/compare}}" title="{{this.Title}}">{{this.Text}}</div>{{/eachList}}</div></div></div></div> <div class="library-song-purchase-date library-song-item-purchase-date">{{formatDate ViewModel.DateAdded "ll"}}</div> <div class="library-song-item-save-karaoke-file-container"> {{#eachList ViewModel.DownloadItems as |downloadItem downloadItemIndex|}} <div class=" {{~#compare @root.karaokeMix.AMix \'===\' downloadItemIndex ~}} library-song-item-save-karaoke-right-file {{~else~}} library-song-item-save-karaoke-left-file {{~/compare~}} "> {{#eachList downloadItem as |item itemIndex|}} {{#compare item.State \'!==\' @root.itemState.Invisible}} <div class="{{apply \'saveItemCSSClass()\' downloadItemIndex item itemIndex}}"> {{!-- State is queued and left part --}} {{#compare (evaluate (getValueFromDictionary ViewModel.States downloadItemIndex noScope=true) \'===\' @root.libraryState.Queued) \'&&\' (evaluate itemIndex \'===\' @root.itemPart.Left)}} {{{item.Text}}} {{else}} <img class="button-image" src="{{getImageSrc item.Icon}}" title="{{item.Title}}"> <div class="button-label">{{{item.Text}}}{{{item.OverText}}}</div> {{/compare}} </div> {{else}} {{!-- Left part and state is adding --}} {{#compare  (evaluate @root.itemPart.Left \'===\' itemIndex) \'&&\' (evaluate @root.libraryState.Adding \'===\' (getValueFromDictionary ViewModel.States downloadItemIndex noScope=true))}} <div class="subview-save-karaoke-{{#compare @root.karaokeMix.AMix \'===\' downloadItemIndex }}right{{else}}left{{/compare}}-file-left-part progress"> <div class="progress-bar" role="progressbar" aria-valuemin="0" aria-valuemax="100"></div> </div> {{/compare}} {{/compare}} {{/eachList}} </div> {{!-- Adding an empty div when in MultiMix --}} {{#compare @root.karaokeMix.MultiMix \'===\' downloadItemIndex}} <div class="library-song-item-save-karaoke-right-file"></div> {{/compare}} {{/eachList}} </div> {{on "click" \'.song-artist-list.library-song-item-artist-value .button:not(.disabled)\' \'ViewModel.ItemViewModel.ArtistItems.at(0).executeAction()\'}} {{on "click" \'.library-song-item-title\' \'ViewModel.ItemViewModel.ShowMoreInfoItem.executeAction()\'}} {{on "click" \'.library-song-item-show-more-info\' \'ViewModel.ItemViewModel.ShowMoreInfoItem.executeAction()\'}} {{updateProgressBar \'.progress-bar\' \'DownloadProgress\'}} {{!-- Check if only 1 column of downloads --}} {{#compare (countList ViewModel.DownloadItems) \'===\' 1}} {{!-- Add/Download action --}} {{on "click" \'.button.has-action.subview-save-karaoke-left-file-left-part\' \'ViewModel.DownloadItems.at(2).at(0).executeAction()\'}} {{!-- Cancel and Remove action --}} {{on "click" \'.button.has-action.subview-save-karaoke-left-file-right-part\' \'ViewModel.DownloadItems.at(2).at(1).executeAction()\'}} {{else}} {{!-- Add/Download action --}} {{on "click" \'.button.has-action.subview-save-karaoke-left-file-left-part\' \'ViewModel.DownloadItems.at(1).at(0).executeAction()\'}} {{on "click" \'.button.has-action.subview-save-karaoke-right-file-left-part\' \'ViewModel.DownloadItems.at(0).at(0).executeAction()\'}} {{!-- Cancel and Remove action --}} {{on "click" \'.button.has-action.subview-save-karaoke-left-file-right-part\' \'ViewModel.DownloadItems.at(1).at(1).executeAction()\'}} {{on "click" \'.button.has-action.subview-save-karaoke-right-file-right-part\' \'ViewModel.DownloadItems.at(0).at(1).executeAction()\'}} {{/compare}} '
});
